var (
  httpRequests = prometheus.NewCounterVec(
    prometheus.CounterOpts{
      Name: "http_requests_total",
      Help: "Total HTTP requests.",
    },
    // Bounded label set: method, route template, status class.
    []string{"method", "route", "status"},
  )
  httpDuration = prometheus.NewHistogramVec(
    prometheus.HistogramOpts{
      Name:    "http_request_duration_seconds",
      Help:    "HTTP request latency.",
      Buckets: prometheus.DefBuckets, // .005 .. 10s
    },
    []string{"route"},
  )
)

func instrument(route string, h http.HandlerFunc) http.HandlerFunc {
  return func(w http.ResponseWriter, r *http.Request) {
    start := time.Now()
    rec := &statusRecorder{ResponseWriter: w, status: 200}
    h(rec, r)
    // route is a TEMPLATE like /users/:id, NEVER the raw path /users/9381.
    httpRequests.WithLabelValues(r.Method, route, strconv.Itoa(rec.status)).Inc()
    httpDuration.WithLabelValues(route).Observe(time.Since(start).Seconds())
  }
}

import { trace, context, propagation } from '@opentelemetry/api';

const tracer = trace.getTracer('checkout-service');

async function chargeCard(order: Order) {
  // startActiveSpan makes this span the current context for the callback.
  return tracer.startActiveSpan('charge_card', async (span) => {
    span.setAttribute('order.id', order.id);
    span.setAttribute('order.amount_cents', order.amountCents);
    try {
      const headers: Record<string, string> = {};
      // Inject the W3C traceparent into outbound call so the payment
      // service's spans link into THIS trace.
      propagation.inject(context.active(), headers);
      const res = await fetch('https://payments/charge', { headers });
      span.setAttribute('http.status_code', res.status);
      return res;
    } catch (err) {
      span.recordException(err as Error);
      span.setStatus({ code: 2 }); // ERROR
      throw err;
    } finally {
      span.end(); // MUST end, or the span leaks and the trace is incomplete.
    }
  });
}

import { trace } from '@opentelemetry/api';
import pino from 'pino';

const logger = pino();

function logWithTrace(level: 'info' | 'error', msg: string, fields: object) {
  const span = trace.getActiveSpan();
  const ctx = span?.spanContext();
  logger[level]({
    ...fields,
    msg,
    trace_id: ctx?.traceId,   // join key back to the trace
    span_id: ctx?.spanId,
  });
}

// Good: structured, queryable, correlatable
logWithTrace('error', 'payment_declined', {
  order_id: 'ord_123', tenant: 'acme', reason: 'insufficient_funds', amount_cents: 4200,
});
// Bad: 'Payment failed for order ord_123 because insufficient_funds'
// — now you need a regex to extract order_id and you lost the trace link.

