import { trace, context, SpanStatusCode } from '@opentelemetry/api';
import { metrics } from '@opentelemetry/api';
import type { Request, Response, NextFunction } from 'express';
import pino from 'pino';

const tracer = trace.getTracer('http-server');
const meter = metrics.getMeter('http-server');
const log = pino();

// RED metrics. Labels are LOW cardinality: route template + status class.
const reqCounter = meter.createCounter('http_requests_total', {
  description: 'Total HTTP requests',
});
const latency = meter.createHistogram('http_request_duration_seconds', {
  description: 'HTTP request latency in seconds',
});

function statusClass(code: number): string {
  return `${Math.floor(code / 100)}xx`; // 200 -> '2xx'
}

// `route` is supplied per-route as a TEMPLATE, e.g. '/users/:id'.
export function observe(route: string) {
  return (req: Request, res: Response, next: NextFunction) => {
    const start = process.hrtime.bigint();

    tracer.startActiveSpan(`${req.method} ${route}`, (span) => {
      span.setAttribute('http.method', req.method);
      span.setAttribute('http.route', route); // template, not raw URL

      res.on('finish', () => {
        const durSec = Number(process.hrtime.bigint() - start) / 1e9;
        const labels = { route, status: statusClass(res.statusCode) };

        reqCounter.add(1, labels);
        latency.record(durSec, { route });

        span.setAttribute('http.status_code', res.statusCode);
        if (res.statusCode >= 500) {
          span.setStatus({ code: SpanStatusCode.ERROR });
        }

        // Structured, correlated log — trace_id joins this to the trace.
        const ctx = span.spanContext();
        log.info({
          msg: 'http_request',
          method: req.method,
          route,                     // never req.url -> cardinality safe
          status: res.statusCode,
          duration_ms: Math.round(durSec * 1000),
          trace_id: ctx.traceId,
          span_id: ctx.spanId,
        });
        span.end();
      });

      // Run the rest of the stack within this span's context so any
      // outbound client auto-instrumentation propagates the same trace.
      context.with(trace.setSpan(context.active(), span), () => next());
    });
  };
}

// Usage: app.get('/users/:id', observe('/users/:id'), getUserHandler);
